/**
 * OpenTelemetry Tracing Middleware
 *
 * Integrates distributed tracing into all API requests.
 * Creates spans for each request with MMS-specific attributes.
 *
 * @see specs/002-architecture.md for observability requirements
 */

import type { Context, Next, MiddlewareHandler } from 'hono';
import { SpanStatusCode } from '@opentelemetry/api';
import { startSpan, recordSpanError } from '../../lib/tracing';
import { getRequestDuration } from './request-context';
import type { AppVariables } from '../types';

/**
 * OpenTelemetry tracing middleware
 *
 * Creates a span for each HTTP request with:
 * - HTTP method and route
 * - Request ID for correlation
 * - Response status code
 * - Duration
 */
export function tracingMiddleware(): MiddlewareHandler<{ Variables: AppVariables }> {
  return async (c: Context<{ Variables: AppVariables }>, next: Next) => {
    const spanName = `HTTP ${c.req.method} ${c.req.routePath || c.req.path}`;

    const span = startSpan(spanName, {
      attributes: {
        'http.method': c.req.method,
        'http.url': c.req.url,
        'http.route': c.req.routePath || c.req.path,
        'http.request_id': c.get('requestId'),
        'http.user_agent': c.req.header('User-Agent') || 'unknown',
      },
    });

    try {
      await next();

      // Add response attributes
      span.setAttribute('http.status_code', c.res.status);
      span.setAttribute('http.duration_ms', getRequestDuration(c));

      // Mark span as error if 5xx response
      if (c.res.status >= 500) {
        span.setStatus({
          code: SpanStatusCode.ERROR,
          message: `HTTP ${c.res.status}`,
        });
      } else {
        span.setStatus({ code: SpanStatusCode.OK });
      }
    } catch (error) {
      recordSpanError(span, error);
      throw error;
    } finally {
      span.end();
    }
  };
}

/**
 * Add user context to current span (call after authentication)
 */
export function addUserContextToSpan(
  span: ReturnType<typeof startSpan>,
  userId: string,
  roles: string[]
): void {
  span.setAttribute('enduser.id', userId);
  span.setAttribute('enduser.roles', roles.join(','));
}

