     1→/**
     2→ * MMS Error Classes
     3→ *
     4→ * Typed error classes for consistent error handling across the application.
     5→ * Each error includes a code for client-side handling and logging.
     6→ *
     7→ * Error code format: CATEGORY_NNN
     8→ * - FILE_001-099: File/CSV processing errors
     9→ * - ROW_001-099: Row/record validation errors
    10→ * - SYS_001-099: System/infrastructure errors
    11→ * - BUS_001-099: Business logic errors
    12→ * - AUTH_001-099: Authentication/authorization errors
    13→ * - EXT_001-099: External system errors (Maximo, etc.)
    14→ *
    15→ * @see specs/004-backend-specification.md Section 4.15
    16→ */
    17→
    18→/**
    19→ * Base error class for all MMS errors
    20→ */
    21→export abstract class MmsError extends Error {
    22→  abstract readonly code: string;
    23→  abstract readonly statusCode: number;
    24→  readonly isOperational: boolean = true;
    25→  readonly timestamp: Date = new Date();
    26→  readonly context?: Record<string, unknown>;
    27→
    28→  constructor(message: string, context?: Record<string, unknown>) {
    29→    super(message);
    30→    this.name = this.constructor.name;
    31→    this.context = context;
    32→    Error.captureStackTrace(this, this.constructor);
    33→  }
    34→
    35→  toJSON() {
    36→    return {
    37→      name: this.name,
    38→      code: this.code,
    39→      message: this.message,
    40→      statusCode: this.statusCode,
    41→      timestamp: this.timestamp.toISOString(),
    42→      ...(this.context && { context: this.context }),
    43→    };
    44→  }
    45→}
    46→
    47→// =============================================================================
    48→// Validation Errors (400)
    49→// =============================================================================
    50→
    51→export class ValidationError extends MmsError {
    52→  readonly code = 'BUS_001';
    53→  readonly statusCode = 400;
    54→  readonly field?: string;
    55→  readonly errors?: Array<{ field: string; message: string }>;
    56→
    57→  constructor(
    58→    message: string,
    59→    options?: {
    60→      field?: string;
    61→      errors?: Array<{ field: string; message: string }>;
    62→      context?: Record<string, unknown>;
    63→    }
    64→  ) {
    65→    super(message, options?.context);
    66→    this.field = options?.field;
    67→    this.errors = options?.errors;
    68→  }
    69→}
    70→
    71→export class CsvValidationError extends MmsError {
    72→  readonly code = 'FILE_001';
    73→  readonly statusCode = 400;
    74→  readonly row?: number;
    75→  readonly column?: string;
    76→
    77→  constructor(
    78→    message: string,
    79→    options?: {
    80→      row?: number;
    81→      column?: string;
    82→      context?: Record<string, unknown>;
    83→    }
    84→  ) {
    85→    super(message, options?.context);
    86→    this.row = options?.row;
    87→    this.column = options?.column;
    88→  }
    89→}
    90→
    91→export class RowValidationError extends MmsError {
    92→  readonly code = 'ROW_001';
    93→  readonly statusCode = 400;
    94→  readonly row: number;
    95→  readonly column?: string;
    96→  readonly value?: unknown;
    97→
    98→  constructor(
    99→    message: string,
   100→    row: number,
   101→    options?: {
   102→      column?: string;
   103→      value?: unknown;
   104→      context?: Record<string, unknown>;
   105→    }
   106→  ) {
   107→    super(message, options?.context);
   108→    this.row = row;
   109→    this.column = options?.column;
   110→    this.value = options?.value;
   111→  }
   112→}
   113→
   114→export class FileError extends MmsError {
   115→  readonly code = 'FILE_002';
   116→  readonly statusCode = 400;
   117→  readonly filePath?: string;
   118→  readonly operation?: string;
   119→
   120→  constructor(
   121→    message: string,
   122→    options?: {
   123→      filePath?: string;
   124→      operation?: string;
   125→      context?: Record<string, unknown>;
   126→    }
   127→  ) {
   128→    super(message, options?.context);
   129→    this.filePath = options?.filePath;
   130→    this.operation = options?.operation;
   131→  }
   132→}
   133→
   134→// =============================================================================
   135→// Authentication Errors (401)
   136→// =============================================================================
   137→
   138→export class AuthenticationError extends MmsError {
   139→  readonly code = 'AUTH_001';
   140→  readonly statusCode = 401;
   141→}
   142→
   143→export class TokenExpiredError extends MmsError {
   144→  readonly code = 'AUTH_002';
   145→  readonly statusCode = 401;
   146→}
   147→
   148→export class InvalidTokenError extends MmsError {
   149→  readonly code = 'AUTH_003';
   150→  readonly statusCode = 401;
   151→}
   152→
   153→// =============================================================================
   154→// Authorization Errors (403)
   155→// =============================================================================
   156→
   157→export class AuthorizationError extends MmsError {
   158→  readonly code = 'AUTH_010';
   159→  readonly statusCode = 403;
   160→  readonly requiredPermission?: string;
   161→
   162→  constructor(
   163→    message: string,
   164→    options?: {
   165→      requiredPermission?: string;
   166→      context?: Record<string, unknown>;
   167→    }
   168→  ) {
   169→    super(message, options?.context);
   170→    this.requiredPermission = options?.requiredPermission;
   171→  }
   172→}
   173→
   174→export class DepotAccessError extends MmsError {
   175→  readonly code = 'AUTH_011';
   176→  readonly statusCode = 403;
   177→  readonly depotId?: string;
   178→
   179→  constructor(message: string, depotId?: string, context?: Record<string, unknown>) {
   180→    super(message, context);
   181→    this.depotId = depotId;
   182→  }
   183→}
   184→
   185→// =============================================================================
   186→// Not Found Errors (404)
   187→// =============================================================================
   188→
   189→export class NotFoundError extends MmsError {
   190→  readonly code: string = 'BUS_010';
   191→  readonly statusCode = 404;
   192→  readonly entityType?: string;
   193→  readonly entityId?: string;
   194→
   195→  constructor(
   196→    message: string,
   197→    options?: {
   198→      entityType?: string;
   199→      entityId?: string;
   200→      context?: Record<string, unknown>;
   201→    }
   202→  ) {
   203→    super(message, options?.context);
   204→    this.entityType = options?.entityType;
   205→    this.entityId = options?.entityId;
   206→  }
