   208→
   209→export class TrainNotFoundError extends NotFoundError {
   210→  readonly code = 'BUS_011';
   211→
   212→  constructor(trainId: string, context?: Record<string, unknown>) {
   213→    super(`Train not found: ${trainId}`, {
   214→      entityType: 'train',
   215→      entityId: trainId,
   216→      context,
   217→    });
   218→  }
   219→}
   220→
   221→export class PmScheduleNotFoundError extends NotFoundError {
   222→  readonly code = 'BUS_012';
   223→
   224→  constructor(scheduleId: string, context?: Record<string, unknown>) {
   225→    super(`PM schedule not found: ${scheduleId}`, {
   226→      entityType: 'pm_schedule',
   227→      entityId: scheduleId,
   228→      context,
   229→    });
   230→  }
   231→}
   232→
   233→// =============================================================================
   234→// Conflict Errors (409)
   235→// =============================================================================
   236→
   237→export class ConflictError extends MmsError {
   238→  readonly code = 'BUS_020';
   239→  readonly statusCode = 409;
   240→}
   241→
   242→export class DuplicateError extends MmsError {
   243→  readonly code = 'BUS_021';
   244→  readonly statusCode = 409;
   245→  readonly field?: string;
   246→  readonly value?: unknown;
   247→
   248→  constructor(
   249→    message: string,
   250→    options?: {
   251→      field?: string;
   252→      value?: unknown;
   253→      context?: Record<string, unknown>;
   254→    }
   255→  ) {
   256→    super(message, options?.context);
   257→    this.field = options?.field;
