   325→  readonly statusCode = 422;
   326→  readonly windowStart?: Date;
   327→  readonly windowEnd?: Date;
   328→  readonly targetDate?: Date;
   329→
   330→  constructor(
   331→    message: string,
   332→    options?: {
   333→      windowStart?: Date;
   334→      windowEnd?: Date;
