    46→  return typeof value === 'string' && HEX_COLOR_REGEX.test(value);
    47→}
    48→
    49→/**
    50→ * Validates positive integer
    51→ */
    52→export function isPositiveInt(value: unknown): value is number {
    53→  return typeof value === 'number' && Number.isInteger(value) && value > 0;
    54→}
    55→
    56→/**
    57→ * Validates non-negative integer
    58→ */
    59→export function isNonNegativeInt(value: unknown): value is number {
    60→  return typeof value === 'number' && Number.isInteger(value) && value >= 0;
    61→}
    62→
    63→/**
    64→ * Validates percentage (0-100)
    65→ */
    66→export function isPercentage(value: unknown): value is number {
    67→  return typeof value === 'number' && value >= 0 && value <= 100;
    68→}
    69→
    70→/**
    71→ * Validates mileage (0 - 10,000,000 km)
    72→ */
    73→export function isValidMileage(value: unknown): value is number {
    74→  return isNonNegativeInt(value) && value <= 10_000_000;
    75→}
