   656→    errors.push({ field: 'commissioning_date', message: 'Date must be in YYYY-MM-DD format' });
   657→  }
   658→
   659→  let fitnessStatus: FitnessStatus | undefined;
   660→  if (fitnessStatusRaw) {
   661→    if (!['FIT', 'RESTRICTED', 'GROUNDED'].includes(fitnessStatusRaw)) {
   662→      errors.push({ field: 'fitness_status', message: 'Invalid fitness status' });
   663→    } else {
   664→      fitnessStatus = fitnessStatusRaw as FitnessStatus;
   665→    }
   666→  }
   667→
   668→  if (errors.length > 0) {
   669→    return { success: false, errors };
   670→  }
   671→
   672→  return {
   673→    success: true,
   674→    data: {
   675→      trainNumber,
