export type ValidationStatus = 'VALID' | 'ANOMALY' | 'PENDING' | 'REJECTED';
export type ReservationType = 'SOFT' | 'HARD';
export type AdjustmentType = 'ADVANCE_PM' | 'DEFER_PM' | 'ADD_OVERTIME' | 'CROSS_DEPOT' | 'ADD_CONTRACTOR' | 'MANUAL_REVIEW';
export type BaselineStatus = 'DRAFT' | 'PUBLISHED' | 'SUPERSEDED';
export type ScenarioStatus = 'ACTIVE' | 'PROMOTED' | 'EXPIRED' | 'DELETED';

