// =============================================================================
// Pagination & Filtering
// =============================================================================

export interface Pagination {
  page: number;
  pageSize: number;
  sort?: string;
  sortDir?: string;
}

export const paginationSchema = createSchema({
  page: 'number',
  pageSize: 'number',
  sort: 'string?',
  sortDir: 'string?',
});

/**
 * Parse pagination with defaults
 */
export function parsePagination(data: unknown): Pagination {
  const parsed = paginationSchema.parse(data) as Pagination;
  return {
    page: isPositiveInt(parsed.page) ? parsed.page : 1,
    pageSize: Math.min(Math.max(parsed.pageSize || 20, 1), 100),
    sort: parsed.sort,
    sortDir: parsed.sortDir === 'desc' ? 'desc' : 'asc',
  };
}

export interface DateRange {
  startDate: string;
  endDate: string;
}

export const dateRangeSchema = createSchema({
  startDate: 'string',
  endDate: 'string',
});

/**
 * Validate date range (start <= end)
 */
export function validateDateRange(range: DateRange): { valid: boolean; message?: string } {
  if (!isValidDateString(range.startDate)) {
    return { valid: false, message: 'Start date must be in YYYY-MM-DD format' };
  }
  if (!isValidDateString(range.endDate)) {
    return { valid: false, message: 'End date must be in YYYY-MM-DD format' };
  }
  if (new Date(range.startDate) > new Date(range.endDate)) {
    return { valid: false, message: 'Start date must be before or equal to end date' };
  }
  return { valid: true };
}

