export interface Train {
  id: string;
  trainNumber: string;
  fleetId: string;
  currentMileageKm: number;
  fitnessStatus: string;
  targetMileageKm?: number;
  displayColor?: string;
}

export interface TrainUpdate {
  fitnessStatus?: string;
  targetMileageKm?: number;
  displayColor?: string;
  restrictions?: string[];
}

export const trainSchema = createSchema({
  id: 'string',
  trainNumber: 'string',
  fleetId: 'string',
  currentMileageKm: 'number',
  fitnessStatus: 'string',
  targetMileageKm: 'number?',
  displayColor: 'string?',
});

export const trainUpdateSchema = createSchema({
  fitnessStatus: 'string?',
  targetMileageKm: 'number?',
  displayColor: 'string?',
  restrictions: 'string[]?',
});

/**
 * Validate train data with full constraint checking
 */
export function validateTrain(train: Train): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!isValidUuid(train.id)) {
    errors.push({ field: 'id', message: 'Invalid UUID format' });
  }
  if (!train.trainNumber || train.trainNumber.length > 20) {
    errors.push({ field: 'trainNumber', message: 'Train number must be 1-20 characters' });
  }
  if (!isValidUuid(train.fleetId)) {
    errors.push({ field: 'fleetId', message: 'Invalid UUID format' });
  }
  if (!isValidMileage(train.currentMileageKm)) {
    errors.push({ field: 'currentMileageKm', message: 'Mileage must be 0-10,000,000 km' });
  }
  if (!['FIT', 'RESTRICTED', 'GROUNDED'].includes(train.fitnessStatus)) {
    errors.push({ field: 'fitnessStatus', message: 'Invalid fitness status' });
  }
  if (train.targetMileageKm !== undefined && !isValidMileage(train.targetMileageKm)) {
    errors.push({ field: 'targetMileageKm', message: 'Mileage must be 0-10,000,000 km' });
  }
  if (train.displayColor !== undefined && !isValidHexColor(train.displayColor)) {
    errors.push({ field: 'displayColor', message: 'Invalid hex color format' });
  }

  return { valid: errors.length === 0, errors };
}

