/**
 * Validate PM schedule create request
 */
export function validatePmScheduleCreate(
  data: PmScheduleCreate
): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!isValidUuid(data.trainId)) {
    errors.push({ field: 'trainId', message: 'Invalid UUID format' });
  }
  if (!isValidUuid(data.pmTypeId)) {
    errors.push({ field: 'pmTypeId', message: 'Invalid UUID format' });
  }
  if (!isValidDateString(data.targetDate)) {
    errors.push({ field: 'targetDate', message: 'Date must be in YYYY-MM-DD format' });
  }
  if (data.assignedDepotId && !isValidUuid(data.assignedDepotId)) {
    errors.push({ field: 'assignedDepotId', message: 'Invalid UUID format' });
  }
  if (data.assignedTrackId && !isValidUuid(data.assignedTrackId)) {
    errors.push({ field: 'assignedTrackId', message: 'Invalid UUID format' });
  }
  if (data.notes && data.notes.length > 1000) {
    errors.push({ field: 'notes', message: 'Notes must be at most 1000 characters' });
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Validate PM schedule move request
 */
export function validatePmScheduleMove(
  data: PmScheduleMove
): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!isValidDateString(data.newTargetDate)) {
    errors.push({ field: 'newTargetDate', message: 'Date must be in YYYY-MM-DD format' });
  }
  if (!data.reason || data.reason.length < 10) {
    errors.push({ field: 'reason', message: 'Reason must be at least 10 characters' });
  }
  if (data.reason && data.reason.length > 500) {
    errors.push({ field: 'reason', message: 'Reason must be at most 500 characters' });
  }

  return { valid: errors.length === 0, errors };
}

