  type: 'RESULT';
  status: 'OPTIMAL' | 'FEASIBLE' | 'INFEASIBLE' | 'TIMEOUT' | 'ERROR';
  objective?: number;
  assignments: OptimizerAssignment[];
  solveTimeMs: number;
  iterations?: number;
}

export type OptimizerOutput = OptimizerProgress | OptimizerHeartbeat | OptimizerError | OptimizerResult;

