  feasible: 'boolean?',
});

export const optimizerHeartbeatSchema = createSchema({
  type: 'string',
  timestamp: 'string',
});

export const optimizerErrorSchema = createSchema({
  type: 'string',
  code: 'string',
  message: 'string',
});

export const optimizerAssignmentSchema = createSchema({
  trainId: 'string',
  routeId: 'string?',
  explanation: 'string?',
});

export const optimizerResultSchema = createSchema({
  type: 'string',
  status: 'string',
  objective: 'number?',
  assignments: 'object[]',
  solveTimeMs: 'number',
  iterations: 'number?',
});

const OPTIMIZER_OUTPUT_TYPES = ['PROGRESS', 'HEARTBEAT', 'ERROR', 'RESULT'] as const;

/**
 * Parse optimizer output message
 */
export function parseOptimizerOutput(
  data: unknown
): { success: true; data: OptimizerOutput } | { success: false; errors: ValidationError[] } {
  if (!data || typeof data !== 'object') {
    return { success: false, errors: [{ field: 'data', message: 'Invalid optimizer output' }] };
  }

  const d = data as Record<string, unknown>;
  const type = d['type'];

  if (!OPTIMIZER_OUTPUT_TYPES.includes(type as (typeof OPTIMIZER_OUTPUT_TYPES)[number])) {
    return { success: false, errors: [{ field: 'type', message: 'Invalid optimizer output type' }] };
  }

  switch (type) {
    case 'PROGRESS':
      return { success: true, data: optimizerProgressSchema.parse(data) as OptimizerProgress };
    case 'HEARTBEAT':
      return { success: true, data: optimizerHeartbeatSchema.parse(data) as OptimizerHeartbeat };
    case 'ERROR':
      return { success: true, data: optimizerErrorSchema.parse(data) as OptimizerError };
    case 'RESULT':
      return { success: true, data: optimizerResultSchema.parse(data) as OptimizerResult };
    default:
      return { success: false, errors: [{ field: 'type', message: 'Unknown output type' }] };
  }
}

/**
 * Validate optimizer input
 */
export function validateOptimizerInput(
  data: OptimizerInput
): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!isValidDateString(data.date)) {
    errors.push({ field: 'date', message: 'Date must be in YYYY-MM-DD format' });
  }
  if (!isValidUuid(data.fleetId)) {
    errors.push({ field: 'fleetId', message: 'Invalid UUID format' });
  }
  if (!Array.isArray(data.trains) || data.trains.length === 0) {
    errors.push({ field: 'trains', message: 'At least one train required' });
  }
  if (!Array.isArray(data.routes) || data.routes.length === 0) {
    errors.push({ field: 'routes', message: 'At least one route required' });
  }

  return { valid: errors.length === 0, errors };
}

// =============================================================================
// API Response Schemas
// =============================================================================

export interface ApiMeta {
  page?: number;
  pageSize?: number;
  total?: number;
  totalPages?: number;
}

export interface ApiSuccessResponse<T> {
  success: true;
  data: T;
  meta?: ApiMeta;
}

export interface ApiErrorDetail {
  code: string;
  message: string;
  details?: Record<string, unknown>;
}

export interface ApiErrorResponse {
  success: false;
  error: ApiErrorDetail;
}

export const apiMetaSchema = createSchema({
  page: 'number?',
  pageSize: 'number?',
  total: 'number?',
  totalPages: 'number?',
});

export const apiSuccessResponseSchema = createSchema({
  success: 'boolean',
  data: 'object',
  meta: 'object?',
});

export const apiErrorDetailSchema = createSchema({
  code: 'string',
  message: 'string',
  details: 'object?',
});

export const apiErrorResponseSchema = createSchema({
  success: 'boolean',
  error: 'object',
});

/**
 * Create API success response
 */
export function createApiSuccessResponse<T>(
  data: T,
  meta?: ApiMeta
): ApiSuccessResponse<T> {
  return {
    success: true,
    data,
    meta,
  };
}

/**
 * Create API error response
 */
export function createApiErrorResponse(
  code: string,
  message: string,
  details?: Record<string, unknown>
): ApiErrorResponse {
  return {
    success: false,
    error: {
      code,
      message,
      details,
    },
  };
}

// =============================================================================
// Auth Schemas
// =============================================================================

export interface LoginRequest {
  email: string;
  password: string;
}

export interface TokenRefreshRequest {
  refreshToken: string;
}

export const loginSchema = createSchema({
  email: 'string',
  password: 'string',
});

export const tokenRefreshSchema = createSchema({
  refreshToken: 'string',
});

const EMAIL_REGEX = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;

/**
 * Validate login request
 */
export function validateLoginRequest(
  data: LoginRequest
): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!data.email || !EMAIL_REGEX.test(data.email)) {
    errors.push({ field: 'email', message: 'Invalid email format' });
  }
  if (!data.password || data.password.length < 8) {
    errors.push({ field: 'password', message: 'Password must be at least 8 characters' });
  }

  return { valid: errors.length === 0, errors };
}

// =============================================================================
// Scenario Schemas
// =============================================================================

export interface ScenarioCreate {
  name: string;
  description?: string;
  forkedFromBaselineId?: string;
  forkedFromScenarioId?: string;
}

export interface ScenarioDelta {
  deltaType: string;
  entityType: string;
  entityId: string;
  oldValues?: Record<string, unknown>;
  newValues: Record<string, unknown>;
  changeReason?: string;
}

export const scenarioCreateSchema = createSchema({
  name: 'string',
  description: 'string?',
  forkedFromBaselineId: 'string?',
  forkedFromScenarioId: 'string?',
});

export const scenarioDeltaSchema = createSchema({
  deltaType: 'string',
  entityType: 'string',
  entityId: 'string',
  oldValues: 'object?',
  newValues: 'object',
  changeReason: 'string?',
});

const DELTA_TYPES = ['PM_MOVE', 'PM_ADD', 'PM_REMOVE', 'CAPACITY_CHANGE', 'TRAIN_STATUS_CHANGE'] as const;

/**
 * Validate scenario create request
 */
export function validateScenarioCreate(
  data: ScenarioCreate
): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!data.name || data.name.length > 100) {
    errors.push({ field: 'name', message: 'Name must be 1-100 characters' });
  }
  if (data.description && data.description.length > 500) {
    errors.push({ field: 'description', message: 'Description must be at most 500 characters' });
  }
  if (data.forkedFromBaselineId && !isValidUuid(data.forkedFromBaselineId)) {
    errors.push({ field: 'forkedFromBaselineId', message: 'Invalid UUID format' });
  }
  if (data.forkedFromScenarioId && !isValidUuid(data.forkedFromScenarioId)) {
    errors.push({ field: 'forkedFromScenarioId', message: 'Invalid UUID format' });
  }

  return { valid: errors.length === 0, errors };
}

/**
 * Validate scenario delta
 */
export function validateScenarioDelta(
  data: ScenarioDelta
): { valid: boolean; errors: ValidationError[] } {
  const errors: ValidationError[] = [];

  if (!DELTA_TYPES.includes(data.deltaType as (typeof DELTA_TYPES)[number])) {
    errors.push({ field: 'deltaType', message: 'Invalid delta type' });
  }
  if (!data.entityType) {
    errors.push({ field: 'entityType', message: 'Entity type required' });
  }
  if (!isValidUuid(data.entityId)) {
    errors.push({ field: 'entityId', message: 'Invalid UUID format' });
  }
  if (!data.newValues || typeof data.newValues !== 'object') {
    errors.push({ field: 'newValues', message: 'New values required' });
  }
  if (data.changeReason && data.changeReason.length > 500) {
    errors.push({ field: 'changeReason', message: 'Change reason must be at most 500 characters' });
  }

  return { valid: errors.length === 0, errors };
}

// =============================================================================
// Validation Helpers
// =============================================================================

/** Validation error structure */
export interface ValidationError {
  field: string;
  message: string;
}

/** Schema validation result */
export type SchemaResult<T> =
  | { success: true; data: T }
  | { success: false; errors: ValidationError[] };

/**
 * Parse and validate data using a schema
 * Compatible with previous Zod-based parseSchema API
 */
export function parseSchema<T>(
  schema: { parse: (data: unknown) => T; isValid?: (data: unknown) => boolean },
  data: unknown
): SchemaResult<T> {
  try {
    const parsed = schema.parse(data);
    return { success: true, data: parsed };
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Validation failed';
    return {
      success: false,
      errors: [{ field: 'root', message }],
    };
  }
}

/**
 * Format validation errors for API response
 * Compatible with previous Zod-based formatZodErrors API
 */
export function formatValidationErrors(
  errors: ValidationError[]
): Array<{ field: string; message: string }> {
  return errors;
}

/**
 * Safe parse helper for compatibility with Zod's safeParse pattern
 */
export function safeParse<T>(
  schema: { parse: (data: unknown) => T },
  data: unknown
): { success: true; data: T } | { success: false; error: { errors: ValidationError[] } } {
  try {
    const parsed = schema.parse(data);
    return { success: true, data: parsed };
  } catch (err) {
    const message = err instanceof Error ? err.message : 'Validation failed';
    return {
      success: false,
      error: {
        errors: [{ field: 'root', message }],
      },
    };
  }
}

// Re-export for backward compatibility
export { invariant };

